class Solution {
    public int[] maximumCount(int[] nums, int[][] queries) {
        int n = nums.length;
        int[] result = new int[queries.length];
        for (int i = 0; i < queries.length; i++) {
            int idx = queries[i][0];
            int val = queries[i][1];
            nums[idx] = val;
            int countPrefix = 0;
            int countSuffix = 0;
            for (int j = 0; j < idx; j++) {
                if (isPrime(nums[j])) {
                    countPrefix++;
                }
            }
            for (int j = idx; j < n; j++) {
                if (isPrime(nums[j])) {
                    countSuffix++;
                }
            }
            result[i] = countPrefix + countSuffix;
        }
        return result;
    }
    private boolean isPrime(int num) {
        if (num <= 1) {
            return false;
        }
        for (int i = 2; i * i <= num; i++) {
            if (num % i == 0) {
                return false;
            }
        }
        return true;
    }
}
